import React, { useState } from 'react';
import './App.css';
import AgentList from './components/AgentList';
import TaskForm from './components/TaskForm';
import TaskList from './components/TaskList';

function App() {
  // State to trigger refresh of task list
  const [refreshTasks, setRefreshTasks] = useState(false);

  // Handle new task submission
  const handleTaskSubmitted = (newTask) => {
    // Trigger refresh of task list
    setRefreshTasks(prev => !prev);
  };

  return (
    <div className="App">
      <header className="app-header">
        <h1>🤖 AI Agent Marketplace</h1>
        <p className="subtitle">A decentralized marketplace powered by Algorand blockchain</p>
      </header>

      <main className="app-main">
        <div className="container">
          {/* Task submission form */}
          <TaskForm onTaskSubmitted={handleTaskSubmitted} />

          {/* Display available agents */}
          <AgentList />

          {/* Display submitted tasks */}
          <TaskList key={refreshTasks} />
        </div>
      </main>

      <footer className="app-footer">
        <p>AI Agent Marketplace © 2026 | Built with React, Node.js & Algorand | TestNet Only</p>
      </footer>
    </div>
  );
}

export default App;
